//! P3 tracking — multi-object tracking over per-frame proposals.
//!
//! Each track carries a decoupled constant-velocity Kalman filter (independent x and y, each a
//! 2-state position/velocity filter), giving smoothed position + velocity + a forward motion
//! model for occlusion coasting. Frame-to-frame data association is solved with the Hungarian
//! algorithm (global optimum), the cost combining predicted-position distance, appearance-
//! signature distance, and bbox IoU, gated so impossible matches can't be forced.
//!
//! Lifecycle: a new proposal seeds a *tentative* track; it becomes *confirmed* after `confirm_hits`
//! consistent frames (the local anti-flicker pre-filter from PLAN.md — distinct from the certified
//! CRDT join in P4); a missed track coasts on its Kalman prediction and is deleted after
//! `max_misses` consecutive misses.

use crate::orientation_spinor::OrientationSpinor;
use crate::recon::describe;
use crate::vision::Proposal;

/// 1-D constant-velocity Kalman (state = [position, velocity], measure position).
#[derive(Clone)]
struct Kalman1D {
    pos: f32,
    vel: f32,
    // 2x2 covariance, row-major.
    p00: f32,
    p01: f32,
    p10: f32,
    p11: f32,
}

impl Kalman1D {
    fn new(pos: f32) -> Self {
        Kalman1D {
            pos,
            vel: 0.0,
            p00: 1.0,
            p01: 0.0,
            p10: 0.0,
            p11: 1.0,
        }
    }

    /// Predict forward by `dt` (seconds). `q` is the process-noise scale.
    fn predict(&mut self, dt: f32, q: f32) {
        // x = F x, F = [[1, dt],[0,1]]
        self.pos += self.vel * dt;
        // P = F P F^T + Q
        let p00 = self.p00 + dt * (self.p10 + self.p01) + dt * dt * self.p11;
        let p01 = self.p01 + dt * self.p11;
        let p10 = self.p10 + dt * self.p11;
        let p11 = self.p11;
        // Process noise (random-acceleration model, coarse).
        self.p00 = p00 + q * dt * dt;
        self.p01 = p01 + q * dt;
        self.p10 = p10 + q * dt;
        self.p11 = p11 + q;
    }

    /// Update with measured position `z`, measurement noise `r`. Returns the innovation (z - pos).
    fn update(&mut self, z: f32, r: f32) -> f32 {
        let y = z - self.pos; // innovation
        let s = self.p00 + r; // innovation covariance (H = [1,0])
        let k0 = self.p00 / s; // Kalman gain
        let k1 = self.p10 / s;
        self.pos += k0 * y;
        self.vel += k1 * y;
        // P = (I - K H) P
        let p00 = (1.0 - k0) * self.p00;
        let p01 = (1.0 - k0) * self.p01;
        let p10 = self.p10 - k1 * self.p00;
        let p11 = self.p11 - k1 * self.p01;
        self.p00 = p00;
        self.p01 = p01;
        self.p10 = p10;
        self.p11 = p11;
        y
    }
}

/// A tracked object.
#[derive(Clone)]
pub struct Track {
    pub id: u64,
    kx: Kalman1D,
    ky: Kalman1D,
    pub bw: f32,
    pub bh: f32,
    pub genus: u32,
    pub sig: [u8; 64],
    /// Principal-axis director of the last matched silhouette (radians, [-pi/2, pi/2], mod-pi).
    /// Headless — see recon::describe. Used by the orientation-spinor analysis (no Kalman on it).
    pub orientation: f32,
    /// Elongation sqrt(lambda_major/lambda_minor) of the last matched silhouette (>= 1).
    pub elongation: f32,
    /// Live orientation-as-spinor state: continuous director lift, winding, half-angle sheet sign,
    /// reliability. Updated each matched step from `orientation`/`elongation`. The in-plane U(1)
    /// sheet recovered from the track PATH (the spinor is the lift) — out-of-plane SU(2) abstains.
    /// See orientation_spinor.rs and docs/spinor-4pi-falsification.md.
    pub spinor: OrientationSpinor,
    pub hits: u32,
    pub misses: u32,
    pub age: u32,
    pub confirmed: bool,
    pub last_pts: f64,
    /// Position history (pts, x, y), capped.
    pub trajectory: Vec<(f64, f32, f32)>,
}

impl Track {
    pub fn x(&self) -> f32 {
        self.kx.pos
    }
    pub fn y(&self) -> f32 {
        self.ky.pos
    }
    /// Velocity in normalised units per second.
    pub fn vx(&self) -> f32 {
        self.kx.vel
    }
    pub fn vy(&self) -> f32 {
        self.ky.vel
    }
    pub fn speed(&self) -> f32 {
        (self.vx() * self.vx() + self.vy() * self.vy()).sqrt()
    }

    /// Test-only: a blank confirmed-capable track at the origin. Lets sibling modules build
    /// synthetic tracks for unit tests without driving the full detect/track pipeline. Not compiled
    /// into the shipped binary; touches no tracking logic.
    #[cfg(test)]
    pub fn for_test(id: u64) -> Track {
        Track {
            id,
            kx: Kalman1D::new(0.0),
            ky: Kalman1D::new(0.0),
            bw: 0.1,
            bh: 0.1,
            genus: 0,
            sig: [0u8; 64],
            orientation: 0.0,
            elongation: 1.0,
            spinor: OrientationSpinor::new(),
            hits: 0,
            misses: 0,
            age: 0,
            confirmed: false,
            last_pts: 0.0,
            trajectory: Vec::new(),
        }
    }

    /// Test-only: seed the Kalman position and first trajectory point (mirrors a track's first match).
    #[cfg(test)]
    pub fn seed_pos(&mut self, x: f32, y: f32, pts: f64) {
        self.kx = Kalman1D::new(x);
        self.ky = Kalman1D::new(y);
        self.last_pts = pts;
        self.trajectory.push((pts, x, y));
    }

    /// Test-only: predict+update the Kalman with a measured position at `pts` and append the
    /// trajectory point (mirrors `Tracker::step`'s matched-track update, so vx()/vy()/speed() and
    /// the trajectory window come out realistic for the dynamical tests).
    #[cfg(test)]
    pub fn push_meas(&mut self, x: f32, y: f32, pts: f64) {
        let dt = (pts - self.last_pts).max(1e-3) as f32;
        self.kx.predict(dt, 0.5);
        self.ky.predict(dt, 0.5);
        self.kx.update(x, 0.01);
        self.ky.update(y, 0.01);
        self.last_pts = pts;
        self.trajectory.push((pts, self.x(), self.y()));
    }
}

#[derive(Debug, Clone)]
pub struct TrackerConfig {
    pub confirm_hits: u32,
    pub max_misses: u32,
    /// Gate radius for association (normalised distance). Matches beyond this are forbidden.
    pub gate: f32,
    /// Cost weights.
    pub w_pos: f32,
    pub w_app: f32,
    pub w_iou: f32,
    /// Kalman process / measurement noise.
    pub q: f32,
    pub r: f32,
    pub max_traj: usize,
}

impl Default for TrackerConfig {
    fn default() -> Self {
        TrackerConfig {
            confirm_hits: 3,
            max_misses: 8,
            gate: 0.18,
            w_pos: 1.0,
            w_app: 0.4,
            w_iou: 0.5,
            q: 0.5,
            r: 0.01,
            max_traj: 512,
        }
    }
}

pub struct Tracker {
    pub tracks: Vec<Track>,
    next_id: u64,
    last_pts: f64,
    started: bool,
    cfg: TrackerConfig,
}

impl Tracker {
    pub fn new(cfg: TrackerConfig) -> Self {
        Tracker {
            tracks: Vec::new(),
            next_id: 1,
            last_pts: 0.0,
            started: false,
            cfg,
        }
    }

    fn sig_dist(a: &[u8; 64], b: &[u8; 64]) -> f32 {
        let mut acc = 0u32;
        for i in 0..64 {
            acc += (a[i] as i32 - b[i] as i32).unsigned_abs();
        }
        acc as f32 / (64.0 * 255.0)
    }

    fn iou(tx: f32, ty: f32, tw: f32, th: f32, p: &Proposal) -> f32 {
        let (ax0, ay0, ax1, ay1) = (tx - tw / 2.0, ty - th / 2.0, tx + tw / 2.0, ty + th / 2.0);
        let (bx0, by0, bx1, by1) = (
            p.cx - p.bw / 2.0,
            p.cy - p.bh / 2.0,
            p.cx + p.bw / 2.0,
            p.cy + p.bh / 2.0,
        );
        let ix = (ax1.min(bx1) - ax0.max(bx0)).max(0.0);
        let iy = (ay1.min(by1) - ay0.max(by0)).max(0.0);
        let inter = ix * iy;
        let ua = tw * th + p.bw * p.bh - inter;
        if ua > 1e-6 { inter / ua } else { 0.0 }
    }

    /// Advance the tracker with this frame's proposals at presentation time `pts`.
    pub fn step(&mut self, proposals: &[Proposal], pts: f64) {
        let dt = if self.started {
            (pts - self.last_pts).max(1e-3) as f32
        } else {
            1.0 / 30.0
        };
        self.started = true;
        self.last_pts = pts;

        // 1. Predict all tracks forward.
        for t in self.tracks.iter_mut() {
            t.kx.predict(dt, self.cfg.q);
            t.ky.predict(dt, self.cfg.q);
            t.age += 1;
        }

        // 2. Cost matrix (tracks x proposals), gated.
        let nt = self.tracks.len();
        let np = proposals.len();
        const BIG: f64 = 1e6;
        let mut cost = vec![vec![BIG; np]; nt];
        for (ti, t) in self.tracks.iter().enumerate() {
            for (pi, p) in proposals.iter().enumerate() {
                let dx = t.x() - p.cx;
                let dy = t.y() - p.cy;
                let pos = (dx * dx + dy * dy).sqrt();
                if pos > self.cfg.gate {
                    continue; // leave BIG -> forbidden
                }
                let app = Self::sig_dist(&t.sig, &p.sig);
                let iou = Self::iou(t.x(), t.y(), t.bw, t.bh, p);
                cost[ti][pi] = (self.cfg.w_pos * pos
                    + self.cfg.w_app * app
                    + self.cfg.w_iou * (1.0 - iou)) as f64;
            }
        }

        // 3. Hungarian assignment.
        let assign = hungarian(&cost, BIG);
        let mut prop_used = vec![false; np];

        // 4. Apply matches.
        for ti in 0..nt {
            if let Some(pi) = assign[ti] {
                if cost[ti][pi] >= BIG {
                    continue; // gated-out "match" — treat as miss
                }
                let p = &proposals[pi];
                prop_used[pi] = true;
                let t = &mut self.tracks[ti];
                t.kx.update(p.cx, self.cfg.r);
                t.ky.update(p.cy, self.cfg.r);
                t.bw = 0.7 * t.bw + 0.3 * p.bw;
                t.bh = 0.7 * t.bh + 0.3 * p.bh;
                t.genus = p.genus;
                let d = describe(p);
                t.orientation = d.orientation;
                t.elongation = d.elongation;
                // Live orientation-spinor lift: one matched director sample (docs §5, done online).
                t.spinor.observe(d.orientation, d.elongation);
                for i in 0..64 {
                    t.sig[i] = ((t.sig[i] as f32) * 0.8 + (p.sig[i] as f32) * 0.2) as u8;
                }
                t.hits += 1;
                t.misses = 0;
                if !t.confirmed && t.hits >= self.cfg.confirm_hits {
                    t.confirmed = true;
                }
                t.last_pts = pts;
                t.trajectory.push((pts, t.x(), t.y()));
                if t.trajectory.len() > self.cfg.max_traj {
                    t.trajectory.remove(0);
                }
            } else {
                self.tracks[ti].misses += 1;
            }
        }
        // Tracks with no assignment row entry also miss (when np==0, assign all None handled above).

        // 5. Spawn tentative tracks for unmatched proposals.
        for (pi, p) in proposals.iter().enumerate() {
            if prop_used[pi] {
                continue;
            }
            let d = describe(p);
            let mut spinor = OrientationSpinor::new();
            spinor.observe(d.orientation, d.elongation);
            let mut t = Track {
                id: self.next_id,
                kx: Kalman1D::new(p.cx),
                ky: Kalman1D::new(p.cy),
                bw: p.bw,
                bh: p.bh,
                genus: p.genus,
                sig: p.sig,
                orientation: d.orientation,
                elongation: d.elongation,
                spinor,
                hits: 1,
                misses: 0,
                age: 1,
                confirmed: self.cfg.confirm_hits <= 1,
                last_pts: pts,
                trajectory: Vec::new(),
            };
            t.trajectory.push((pts, p.cx, p.cy));
            self.next_id += 1;
            self.tracks.push(t);
        }

        // 6. Cull dead tracks.
        let max_misses = self.cfg.max_misses;
        self.tracks.retain(|t| t.misses <= max_misses);
    }

    /// Confirmed tracks only.
    pub fn confirmed(&self) -> impl Iterator<Item = &Track> {
        self.tracks.iter().filter(|t| t.confirmed)
    }
}

/// Hungarian (Kuhn–Munkres) assignment minimising total cost. Rectangular `cost[row][col]`
/// (rows = tracks, cols = proposals). Returns, per row, the assigned column (or None). Costs of
/// `forbidden` or greater are treated as non-edges and won't be chosen unless unavoidable.
fn hungarian(cost: &[Vec<f64>], forbidden: f64) -> Vec<Option<usize>> {
    let n = cost.len();
    if n == 0 {
        return Vec::new();
    }
    let m = cost[0].len();
    if m == 0 {
        return vec![None; n];
    }
    // Pad to square with the larger of the two dims.
    let dim = n.max(m);
    // Potentials method (1-indexed) over a dim x dim matrix.
    let mut a = vec![vec![0.0f64; dim]; dim];
    for i in 0..dim {
        for j in 0..dim {
            a[i][j] = if i < n && j < m { cost[i][j] } else { forbidden };
        }
    }
    let inf = f64::INFINITY;
    let mut u = vec![0.0f64; dim + 1];
    let mut v = vec![0.0f64; dim + 1];
    let mut p = vec![0usize; dim + 1]; // p[j] = row assigned to col j (1-indexed rows)
    let mut way = vec![0usize; dim + 1];
    for i in 1..=dim {
        p[0] = i;
        let mut j0 = 0usize;
        let mut minv = vec![inf; dim + 1];
        let mut used = vec![false; dim + 1];
        loop {
            used[j0] = true;
            let i0 = p[j0];
            let mut delta = inf;
            let mut j1 = 0usize;
            for j in 1..=dim {
                if !used[j] {
                    let cur = a[i0 - 1][j - 1] - u[i0] - v[j];
                    if cur < minv[j] {
                        minv[j] = cur;
                        way[j] = j0;
                    }
                    if minv[j] < delta {
                        delta = minv[j];
                        j1 = j;
                    }
                }
            }
            for j in 0..=dim {
                if used[j] {
                    u[p[j]] += delta;
                    v[j] -= delta;
                } else {
                    minv[j] -= delta;
                }
            }
            j0 = j1;
            if p[j0] == 0 {
                break;
            }
        }
        loop {
            let j1 = way[j0];
            p[j0] = p[j1];
            j0 = j1;
            if j0 == 0 {
                break;
            }
        }
    }
    // p[j] = row (1-indexed) assigned to col j. Invert to row->col.
    let mut row_col = vec![None; n];
    for j in 1..=dim {
        let i = p[j];
        if i >= 1 && i <= n && j <= m {
            row_col[i - 1] = Some(j - 1);
        }
    }
    row_col
}
